external_knowledge:
- Larger charter schools: Schools with more than 500 students; 
- Estimated budget per student: Calculated by dividing the total budget by the number of students;
- Ratio of students to staff members: Computed by dividing the number of unique students by the number of unique staff members.

sql:
SELECT GROUP_CONCAT(school_name)
FROM schools
WHERE size = (SELECT MAX(size) FROM schools);

SELECT MAX(budget) 
FROM schools 
WHERE size > 1000;

SELECT principals.name AS principal_name, schools.school_name
FROM schools
INNER JOIN principals ON schools.principal_id = principals.principal_id;

SELECT schools.school_name, facilities.facility_name, facilities.capacity
FROM facilities
JOIN schools ON schools.school_id = facilities.school_id;
